// Apollo Org Discovery — config. One request PER keyword tag (Apollo AND-s
// multiple tags, which over-narrows). Geo is done SERVER-SIDE via
// organization_locations (Apollo omits city from most records, so we must NOT
// filter location on the response). VERTICAL picks the vertical.
const VERTICAL = "lastmile";   // "lastmile" | "fashion_district"
const PRESETS = {
  lastmile: {
    locations: ["Los Angeles, California","Orange County, California","San Diego, California","Riverside, California","San Bernardino, California","Ventura, California","Long Beach, California","Ontario, California"],
    keyword_tags: ["courier","last mile delivery","final mile","parcel delivery","package delivery","same day delivery","delivery service","logistics","transportation","freight"],
    employee_ranges: ["1,10","11,20","21,50","51,100","101,200","201,500","501,1000"],
    pages: 2
  },
  fashion_district: {
    locations: ["Los Angeles, California"],
    keyword_tags: ["apparel","wholesale apparel","women's clothing","fashion","textiles","clothing manufacturer","importer"],
    employee_ranges: ["1,10","11,20","21,50","51,100","101,200"],
    pages: 2
  }
};
const P = PRESETS[VERTICAL];
const out = [];
for (const tag of P.keyword_tags) {
  for (let p = 1; p <= P.pages; p++) {
    out.push({ json: { _vertical: VERTICAL, _tag: tag, body: {
      organization_locations: P.locations,
      q_organization_keyword_tags: [tag],
      organization_num_employees_ranges: P.employee_ranges,
      page: p, per_page: 100
    } } });
  }
}
return out;

// Dedupe by domain, drop obvious non-carriers, keep everything Apollo returned
// (geo is already done server-side; Apollo omits city on most records so we do
// NOT geo-filter the response). VERTICAL read from the config node.
const VERTICAL = $('Org-search config').first().json._vertical;
const FP = {
  lastmile: {
    socal:true,
    priority_cities: ["ontario","fontana","city of industry","rancho cucamonga","riverside","san bernardino","jurupa valley","rialto","colton","moreno valley","perris","redlands","chino","mira loma","eastvale"],
    fit_keywords: ["last mile","final mile","courier","parcel","delivery","dispatch","express"],
    deny: ["software","technologies"," saas","consulting","staffing","recruit","marketing agency"],
    label: "Last-Mile / Courier (SoCal)", name_flag: null
  },
  fashion_district: {
    zip5: ["90014","90015","90021","90013","90079","90017"],
    priority_cities: [], fit_keywords: [], deny: [],
    label: "Apparel/Textile (Fashion District)", name_flag: "korean"
  }
};
const P = FP[VERTICAL];
function inGeo(o){
  if (P.zip5){ const z=String(o.postal_code||"").slice(0,5); return P.zip5.includes(z); }
  const st=String(o.state||"").toLowerCase();
  return !(st && !(st==="ca"||st.includes("calif")));   // server already constrained to CA; just guard strays
}
const KSUR = new Set(["kim","lee","park","choi","cho","jung","jeong","kang","yoon","yun","jang","lim","im","han","oh","seo","suh","shin","kwon","hwang","ahn","an","song","yang","bae","baek","nam","noh","roh","ha","koo","ku","min","moon","yu","yoo","ryu","chung","jeon","jun","ko","go","sung","seong","hong","jin","cha","chu","joo","ju"]);
const seen = new Set();
const result = [];
for (const it of items) {
  const j = it.json || {};
  const orgs = [].concat(j.organizations||[], j.accounts||[]);
  for (const o of orgs) {
    if (!inGeo(o)) continue;
    const nm=(o.name||"").toLowerCase();
    if ((P.deny||[]).some(x=>nm.includes(x))) continue;        // drop obvious software/agency noise
    const d = (o.primary_domain||o.website_url||"").replace(/^https?:\/\//,"").replace(/^www\./,"").replace(/\/.*$/,"").toLowerCase();
    if (!d || seen.has(d)) continue;
    seen.add(d);
    const city=(o.city||"").toLowerCase();
    const blob=((o.name||"")+" "+(o.industry||"")).toLowerCase();
    const priority=(P.priority_cities||[]).some(c=>city.includes(c));
    const fit=(P.fit_keywords||[]).some(k=>blob.includes(k));
    let nameFlag=false,nameSig="";
    if(P.name_flag==="korean"){ for(const w of (o.name||"").toLowerCase().split(/[^a-z]+/)) if(KSUR.has(w)){nameFlag=true;nameSig="surname:"+w;} }
    result.push({ json: { c:o.name, d, city:o.city||"", st:"CA", t:o.estimated_num_employees||0, ind:P.label, zip:String(o.postal_code||"").slice(0,5), address:o.street_address||o.raw_address||"", employees:o.estimated_num_employees||null, org_id:o.id||null, prospect_source:"apollo_org_discovery_"+VERTICAL, priority, fit, name_flag:nameFlag, name_signal:nameSig } });
  }
}
result.sort((a,b)=>(b.json.priority-a.json.priority)||(b.json.fit-a.json.fit));
return result;

// Paste-ready wf12 array + a _debug block read straight from the raw Apollo
// responses, so we can diagnose recall/geo without hunting nodes in n8n.
const raw = $('Apollo Org Search').all().map(i => i.json);
let totalOrgs=0, withCity=0, withState=0, caCount=0, withZip=0;
const states={}; let sample=null;
for (const r of raw) {
  const orgs = [].concat(r.organizations||[], r.accounts||[]);
  totalOrgs += orgs.length;
  for (const o of orgs) {
    if (!sample) sample = { keys:Object.keys(o).slice(0,40), name:o.name, city:o.city, state:o.state, country:o.country, postal_code:o.postal_code, primary_domain:o.primary_domain };
    if (o.city) withCity++;
    if (o.postal_code) withZip++;
    if (o.state){ withState++; const s=String(o.state); states[s]=(states[s]||0)+1; }
    const st=String(o.state||'').toLowerCase();
    if (st==='ca'||st.includes('calif')) caCount++;
  }
}
const firstResp = raw[0] || {};
const rows = items.map(i=>i.json).filter(r=>r.d);
const arr = rows.map(r=>`  {c:${JSON.stringify(r.c)},d:${JSON.stringify(r.d)},city:${JSON.stringify(r.city)},st:'CA',t:${r.t||0},ind:${JSON.stringify(r.ind)}},`).join("\n");
return [{ json: {
  count: rows.length,
  _debug: {
    responses: raw.length,
    firstResp_keys: Object.keys(firstResp),
    pagination: firstResp.pagination || null,
    totalOrgs, withCity, withZip, withState, caCount,
    topStates: Object.entries(states).sort((a,b)=>b[1]-a[1]).slice(0,10),
    sample
  },
  paste: "const companies = [\n"+arr+"\n];"
} }];
